  const rawPayload = input.raw_payload || {};
  const hydratedEmail = rawPayload._instantly_hydrated_email || {};
  const firstText = (...values) => { for (const v of values) { const s = String(v == null ? '' : v).trim(); if (s && s !== '{}' && s !== '[]') return s; } return ''; };
  const text = firstText(reply.text, reply.snippet, rawPayload.reply_text, rawPayload.reply_text_snippet, hydratedEmail.reply_text, hydratedEmail.text, hydratedEmail.content_preview, hydratedEmail.body && hydratedEmail.body.text).toLowerCase();
  const combined = `${subject} ${text}`;
  const fromEmail = String(reply.from_address_email || '').toLowerCase();
  const hasAttachments = reply.has_attachments === true || prefilter.has_attachments === true;

  const flags = {};

  flags['det-unsub-001'] =
    /\b(unsubscribe|opt out|opt-out|stop emailing me|remove me from (this|your) (list|mailing list)|take me off (this|your) list|do not contact me again)\b/.test(combined)
    || prefilter.is_unsubscribe_language === true;

  flags['det-legal-001'] =
    /(gdpr|ccpa|hipaa|privacy act|data protection|right to be forgotten|where did you get my (email|data|information))/.test(combined);

  flags['det-legal-002'] =
    /\b(attorney|lawyer|legal counsel|lawsuit|cease and desist|c&d)\b/.test(combined);

  flags['det-regulator-001'] =
    /(\bftc\b|\bico\b|reporting you to|filing a complaint with)/.test(combined);

  flags['det-hostile-001'] = containsAny(combined, HOSTILE_THREAT_TERMS);

  flags['det-media-001'] =
    /(journalist|reporter|the press|writing an article about)/.test(combined);

  flags['det-hostile-002'] =
    containsAny(combined, PROFANITY_TERMS) || /\b(threat|threatening) you\b/.test(combined);

  flags['det-complaint-001'] =
    /(this is spam|reported you|reporting this to|continued contact after|i (have|already) (asked|told) you to stop)/.test(combined);

  const dsnEvidence = /(undeliverable|delivery status notification|delivery (has )?failed|mail delivery failed|returned to sender)/.test(combined);
  flags['det-bounce-001'] =
    (fromEmail.includes('mailer-daemon') || fromEmail.includes('postmaster')) && dsnEvidence;
  flags['det-bounce-002'] =
    !flags['det-bounce-001'] && dsnEvidence && (prefilter.is_bounce === true || /\b(dsn|mailer-daemon|postmaster)\b/.test(combined));

  flags['det-ooo-001'] =
    /(out of (the )?office|on vacation|on holiday|on leave|on sabbatical|automatic reply|auto[- ]?reply|away from (the )?office|currently away)/.test(combined)
    || prefilter.is_out_of_office === true;

  flags['det-price-001'] =
    /\b(price|pricing|cost|quote|rfp|rfi|contract|msa|sow|discount|enterprise pricing)\b/.test(combined);

  flags['det-attach-001'] = hasAttachments;

  flags['det-booking-001'] =
    /(book a time|book a call|send (me |us )?(a |your )?calendar|schedule a call|calendly|here.s my availability|i.m available (on|at))/.test(combined)
    && !flags['det-price-001'] && !flags['det-attach-001'];

  flags['det-referral-001'] =
    /(please contact|please reach out to|reach out to|talk to|forward you to|the right person (is|would be)|this is handled by|loop in)/.test(combined);

  flags['det-wrong-001'] =
    /(wrong person|wrong address|not the right person|not in that role|no longer work (here|there)|not with that company anymore)/.test(combined)
    && !flags['det-referral-001'];

  const opFlags = {
    is_unsupported_event_type: prefilter.is_unsupported_event_type === true,
    is_malformed_payload: prefilter.is_malformed_payload === true,
    is_duplicate_event: prefilter.is_duplicate_event === true,
    is_self_sent: prefilter.is_self_sent === true,
    is_empty_reply: prefilter.is_empty_reply === true,
    is_automated_response: prefilter.is_automated_response === true,
    campaign_cell_mismatch: prefilter.campaign_cell_mismatch === true
  };

  let category = null;
  let ruleId = null;
  let noopMatch = false;
  let deterministicMatch = false;

  if (opFlags.is_duplicate_event || opFlags.is_self_sent) {
    noopMatch = true;
    category = null;
    ruleId = opFlags.is_duplicate_event ? 'op-duplicate' : 'op-self-sent';
  } else if (opFlags.is_malformed_payload || opFlags.is_unsupported_event_type) {
    category = 'OTHER';
    ruleId = opFlags.is_malformed_payload ? 'op-malformed' : 'op-unsupported-event';
    deterministicMatch = true;
  } else if (flags['det-unsub-001']) {
    category = 'UNSUBSCRIBE'; ruleId = 'det-unsub-001'; deterministicMatch = true;
  } else if (flags['det-legal-001']) {
    category = 'LEGAL_PRIVACY_OR_COMPLAINT'; ruleId = 'det-legal-001'; deterministicMatch = true;
  } else if (flags['det-legal-002']) {
    category = 'LEGAL_PRIVACY_OR_COMPLAINT'; ruleId = 'det-legal-002'; deterministicMatch = true;
  } else if (flags['det-regulator-001']) {
    category = 'LEGAL_PRIVACY_OR_COMPLAINT'; ruleId = 'det-regulator-001'; deterministicMatch = true;
  } else if (flags['det-hostile-001']) {
    category = 'HOSTILE_OR_REPUTATIONAL_RISK'; ruleId = 'det-hostile-001'; deterministicMatch = true;
  } else if (flags['det-hostile-002']) {
    category = 'HOSTILE_OR_REPUTATIONAL_RISK'; ruleId = 'det-hostile-002'; deterministicMatch = true;
  } else if (flags['det-complaint-001']) {
    category = 'LEGAL_PRIVACY_OR_COMPLAINT'; ruleId = 'det-complaint-001'; deterministicMatch = true;
  } else if (flags['det-attach-001']) {
    category = 'ATTACHMENT_REQUIRES_REVIEW'; ruleId = 'det-attach-001'; deterministicMatch = true;
  } else if (flags['det-bounce-001']) {
    category = 'BOUNCE_OR_DELIVERY_NOTICE'; ruleId = 'det-bounce-001'; deterministicMatch = true;
  } else if (flags['det-bounce-002']) {
    category = 'BOUNCE_OR_DELIVERY_NOTICE'; ruleId = 'det-bounce-002'; deterministicMatch = true;
  } else if (flags['det-ooo-001']) {
    category = 'OUT_OF_OFFICE'; ruleId = 'det-ooo-001'; deterministicMatch = true;
  } else if (flags['det-price-001']) {
    category = 'PRICING_OR_COMMERCIAL_NEGOTIATION'; ruleId = 'det-price-001'; deterministicMatch = true;
  } else if (flags['det-booking-001']) {
    category = 'BOOKING_REQUEST'; ruleId = 'det-booking-001'; deterministicMatch = true;
  } else if (flags['det-referral-001']) {
    category = 'REFERRAL'; ruleId = 'det-referral-001'; deterministicMatch = true;
  } else if (flags['det-wrong-001']) {
    category = 'WRONG_PERSON'; ruleId = 'det-wrong-001'; deterministicMatch = true;
  } else if (opFlags.is_empty_reply) {
    category = 'AMBIGUOUS'; ruleId = 'op-empty-reply'; deterministicMatch = true;
  }

  return {
    json: {
      ...input,
      deterministic: {
        flags,
        media_flag: flags['det-media-001'],
        operational_flags: opFlags,
        category,
        rule_id: ruleId,
        deterministic_match: deterministicMatch,
        noop_match: noopMatch
      }
    }
  };
});

const items = $input.all();

const KB_REFERENCE = 'KB-1.0-DRAFT';

function extractQuestions(text) {
  if (!text) return [];
  return text.split(/(?<=[.!?])\s+/).map(s => s.trim()).filter(s => s.endsWith('?')).slice(0, 5);
}

function emptyValidationLearning(nes) {
  const vl = (nes && nes.validation_learning_seed) || {};
  return {
    pain_confirmed: vl.pain_confirmed ?? 'unknown',
    current_outbound_spend_confirmed: vl.current_outbound_spend_confirmed ?? 'unknown',
    capacity_problem_confirmed: vl.capacity_problem_confirmed ?? 'unknown',
    proof_objection: vl.proof_objection ?? 'unknown',
    pricing_interest: vl.pricing_interest ?? 'unknown',
    alpha_interest: vl.alpha_interest ?? 'unknown',
    decision_maker_confirmed: vl.decision_maker_confirmed ?? 'unknown',
    discovery_call_booked: vl.discovery_call_booked ?? 'unknown',
    discovery_call_showed: vl.discovery_call_showed ?? 'unknown',
    validation_signal_strength: vl.validation_signal_strength ?? 'unknown',
    voice_of_customer_excerpt: vl.voice_of_customer_excerpt ?? null
  };
}

function riskFlagsFor(category, det) {
  const flags = [];
  const df = det.flags || {};
  if (category === 'LEGAL_PRIVACY_OR_COMPLAINT') {
    if (df['det-legal-001']) { flags.push('privacy'); flags.push('legal'); }
    if (df['det-legal-002']) flags.push('legal');
    if (df['det-regulator-001']) { flags.push('legal'); flags.push('regulatory'); }
    if (df['det-complaint-001']) flags.push('complaint');
  }
  if (category === 'HOSTILE_OR_REPUTATIONAL_RISK') { flags.push('hostile'); flags.push('reputational'); }
  if (category === 'ATTACHMENT_REQUIRES_REVIEW') flags.push('attachment');
  if (category === 'PRICING_OR_COMMERCIAL_NEGOTIATION') flags.push('commercial');
  if (det.media_flag === true && !flags.includes('media')) flags.push('media');
  return [...new Set(flags)];
}

function requestedActionFor(category) {
  const map = {
    POSITIVE_INTEREST:'AWAIT_NEXT_STEPS', INFORMATION_REQUEST:'ANSWER_QUESTIONS',
    BOOKING_REQUEST:'SCHEDULE_CALL', TIMING_OBJECTION:'FOLLOW_UP_LATER',
    REFERRAL:'CONTACT_REFERRED_PERSON', NOT_INTERESTED:'STOP_CONTACT',
    UNSUBSCRIBE:'STOP_ALL_CONTACT', OUT_OF_OFFICE:'NONE',
    BOUNCE_OR_DELIVERY_NOTICE:'NONE', WRONG_PERSON:'STOP_CONTACT_THIS_PERSON',
    PRICING_OR_COMMERCIAL_NEGOTIATION:'PROVIDE_PRICING',
    LEGAL_PRIVACY_OR_COMPLAINT:'ESCALATE', HOSTILE_OR_REPUTATIONAL_RISK:'ESCALATE',
    ATTACHMENT_REQUIRES_REVIEW:'REVIEW_ATTACHMENT', AMBIGUOUS:'CLARIFY', OTHER:'NONE'
  };
  return map[category] || 'NONE';
}

function permittedAutomationFor(category) {
  if (['POSITIVE_INTEREST','INFORMATION_REQUEST'].includes(category)) return 'AI_DRAFT';
  if (['BOOKING_REQUEST','TIMING_OBJECTION','REFERRAL','NOT_INTERESTED','UNSUBSCRIBE','WRONG_PERSON'].includes(category)) return 'TEMPLATE_DRAFT';
  return 'NONE';
}

function interestStageFor(category) {
  if (category === 'INFORMATION_REQUEST') return 'DISCOVERY_ONLY';
  if (category === 'POSITIVE_INTEREST' || category === 'BOOKING_REQUEST') return 'VALIDATION_SPRINT_INTEREST';
  return 'UNKNOWN';
}

function deterministicHeuristicClassify(combined) {
  const trimmed = combined.trim();
  const wordCount = trimmed.split(/\s+/).filter(Boolean).length;
  const notInterestedRx = /\b(not interested|no thank you|no thanks|we're not interested|we are not interested|not a fit|not for us|please remove (me|us)|we'll pass|we will pass)\b/;
  const timingRx = /\b(not (the )?right time|maybe (next|in a few)|circle back|check back|reach out again|follow up (in|next)|touch base (in|next)|revisit (this|in)|down the (road|line)|next (quarter|month|year))\b/;
  const positiveRx = /\b(sounds (interesting|good|great)|interested|tell me more|would like to (learn|hear) more|keen to|let's (chat|talk|connect)|happy to (chat|talk|discuss)|sure[, ]|yes[, ]|definitely)\b/;
  const infoRx = /\?|\b(how does (this|it) work|what is|can you explain|more (information|details)|how (do|would) (you|this)|what's the (process|mechanism)|tell me (about|how))\b/;
  if (notInterestedRx.test(trimmed)) return { category:'NOT_INTERESTED', confidence:0.75, evidence:['keyword: decline phrase'] };
  if (timingRx.test(trimmed))        return { category:'TIMING_OBJECTION', confidence:0.75, evidence:['keyword: timing/deferral phrase'] };
  if (infoRx.test(trimmed))          return { category:'INFORMATION_REQUEST', confidence:0.75, evidence:['keyword: question or info-seeking phrase'] };
  if (positiveRx.test(trimmed))      return { category:'POSITIVE_INTEREST', confidence:0.75, evidence:['keyword: positive-interest phrase'] };
  return {
    category:'AMBIGUOUS', confidence: wordCount === 0 ? 0.3 : 0.5,
    evidence: wordCount === 0 ? ['empty/whitespace reply'] : ['no deterministic or keyword match']
  };
}

// ── MICRO INTENT DETECTION ─────────────────────────────────────────────────
function detectMicroIntent(category, detFlags, text) {
  const t = (text || '').toLowerCase();
  if (!category) return 'AMBIGUOUS_SHORT_REPLY';
  if (category === 'UNSUBSCRIBE' || category === 'LEGAL_PRIVACY_OR_COMPLAINT') return 'UNSUBSCRIBE_OR_COMPLAINT';
  if (category === 'HOSTILE_OR_REPUTATIONAL_RISK') return 'ANGRY_COMPLAINT';
  if (category === 'OUT_OF_OFFICE' || category === 'BOUNCE_OR_DELIVERY_NOTICE') return 'OOO_AUTO_REPLY';
  if (category === 'WRONG_PERSON') return 'WRONG_PERSON';
  if (category === 'NOT_INTERESTED') return 'NOT_INTERESTED';
  if (category === 'BOOKING_REQUEST') return 'MEETING_TIME_REQUEST';
  if (category === 'PRICING_OR_COMMERCIAL_NEGOTIATION') return 'PRICING_REQUEST';
  if (category === 'TIMING_OBJECTION') return 'NOT_NOW';
  if (category === 'REFERRAL') return 'WRONG_PERSON';
  if (category === 'ATTACHMENT_REQUIRES_REVIEW' || category === 'OTHER') return 'AMBIGUOUS_SHORT_REPLY';
  // Text-based for POSITIVE_INTEREST, INFORMATION_REQUEST, AMBIGUOUS
  if (/\b(proof|case stud|result|evidence|testimonial|reference|customer|client|you done this|worked with|do you have any)\b/.test(t)) return 'PROOF_OR_CASE_STUDY_REQUEST';
  if (/\b(how does (it|this) work|how (do|would) you|what.s the process|mechanism|methodology|how is this (different|better))\b/.test(t)) return 'HOW_IT_WORKS_REQUEST';
  if (/\b(what (are|is) (your?|you) (offer|service|product|doing)|tell me more|more (info|information|detail)|explain|what.s this about|what (do|does) (you|it) (do|provide))\b/.test(t)) return 'OFFER_EXPLANATION';
  if (/\b(we (already|currently) (have|use|run|do)|we.ve (got|been)|our (agency|team|vendor|provider|sdrs?)|outbound (running|already|team)|in-?house outbound)\b/.test(t)) return 'CURRENT_OUTBOUND_VENDOR';
  if (/\b(price|pricing|cost|budget|invest|fee|rate|quote|proposal|what does it (cost|run))\b/.test(t)) return 'PRICING_REQUEST';
  const wc = t.trim().split(/\s+/).filter(Boolean).length;
  if (wc <= 4) return 'AMBIGUOUS_SHORT_REPLY';
  if (category === 'POSITIVE_INTEREST') return 'POSITIVE_INTEREST_GENERAL';
  if (category === 'INFORMATION_REQUEST') return 'OFFER_EXPLANATION';
  return 'AMBIGUOUS_SHORT_REPLY';
}

function draftPolicyFor(mi) {
  const p = {
    MEETING_TIME_REQUEST:      'FIXED_TEMPLATE',
    PROOF_OR_CASE_STUDY_REQUEST:'AI_SUPERVISED_OR_TEMPLATE',
    OFFER_EXPLANATION:         'AI_SUPERVISED_OR_TEMPLATE',
    HOW_IT_WORKS_REQUEST:      'AI_SUPERVISED_OR_TEMPLATE',
    CURRENT_OUTBOUND_VENDOR:   'AI_SUPERVISED_OR_TEMPLATE',
    PRICING_REQUEST:           'HUMAN_ONLY',
    NOT_NOW:                   'FIXED_TEMPLATE',
    NOT_INTERESTED:            'FIXED_TEMPLATE',
    UNSUBSCRIBE_OR_COMPLAINT:  'FIXED_TEMPLATE_SUPPRESS_ONLY',
    WRONG_PERSON:              'FIXED_TEMPLATE',
    AMBIGUOUS_SHORT_REPLY:     'AI_SUPERVISED_OR_TEMPLATE',
    OOO_AUTO_REPLY:            'NO_DRAFT',
    ANGRY_COMPLAINT:           'HUMAN_ONLY',
    POSITIVE_INTEREST_GENERAL: 'AI_SUPERVISED_OR_TEMPLATE'
  };
  return p[mi] || 'HUMAN_ONLY';
}

return items.map(item => {
  const input = item.json || {};
  const det = input.deterministic || { flags:{}, operational_flags:{} };
  const nes = input.nes || {};
  const reply = nes.reply || {};
  const campaignContext = nes.campaign_context || {};

  const subject = String(reply.subject || '');
  const text    = String(reply.text    || '');
  const combined = `${subject} ${text}`.toLowerCase();

  const classifierInputs = {
    model: 'deterministic-heuristic-1.0',
    kb_reference: KB_REFERENCE,
    thread_context: 'NOT_AVAILABLE',
    validation_cell: campaignContext.validation_cell || 'UNKNOWN',
    campaign_message_variant: campaignContext.campaign_message_variant || 'UNKNOWN'
  };

  const replyLanguage    = String(reply.language || '').toLowerCase();
  const isEnglish        = !replyLanguage || replyLanguage === 'en' || replyLanguage === 'eng' || replyLanguage.startsWith('en-');

  let result, decisionPath;
  if (det.noop_match === true) {
    result = { category:null, confidence:1, evidence:[`operational rule ${det.rule_id} matched`] };
    decisionPath = 'OPERATIONAL_NOOP';
  } else if (det.deterministic_match === true) {
    result = { category:det.category, confidence:1, evidence:[`deterministic rule ${det.rule_id} matched`] };
    decisionPath = 'DETERMINISTIC_RULE';
  } else if (!isEnglish) {
    result = { category:'AMBIGUOUS', confidence:0.3, evidence:[`non-English reply (${replyLanguage||'unknown'})`] };
    decisionPath = 'NON_ENGLISH_FALLBACK_T15';
  } else {
    result = deterministicHeuristicClassify(combined);
    decisionPath = 'DETERMINISTIC_HEURISTIC_CLASSIFIER';
  }

  const category = result.category;
  const microIntent = detectMicroIntent(category, det.flags || {}, text);
  const draftPolicy = draftPolicyFor(microIntent);

  const decisionTrace = {
    path: decisionPath, rule_id: det.rule_id || null, language: replyLanguage || 'unknown',
    classifier_version: 'deterministic-heuristic-1.0', policy_version: nes.policy_version || 'policy-HMZ-1.2'
  };

  const classifier = {
    ...classifierInputs, category, confidence: result.confidence, evidence: result.evidence,
    classifier_version: 'deterministic-heuristic-1.0', decision_trace: decisionTrace,
    detected_questions: category === 'INFORMATION_REQUEST' ? extractQuestions(text) : [],
    requested_action: category ? requestedActionFor(category) : 'NONE',
    risk_flags: category ? riskFlagsFor(category, det) : (det.media_flag ? ['media'] : []),
    permitted_automation_action: det.noop_match ? 'NOOP' : (category ? permittedAutomationFor(category) : 'NONE'),
    interest_stage: category ? interestStageFor(category) : 'UNKNOWN',
    validation_learning: emptyValidationLearning(nes),
    micro_intent: microIntent,
    draft_policy: draftPolicy
  };

  if (classifier.validation_learning.voice_of_customer_excerpt == null && combined.trim().length > 0) {
    const src = text.trim().length > 0 ? text.trim() : subject.trim();
    classifier.validation_learning.voice_of_customer_excerpt = src.length > 240 ? src.slice(0, 240) + '...' : src;
  }
  if (category === 'PRICING_OR_COMMERCIAL_NEGOTIATION' && classifier.validation_learning.pricing_interest === 'unknown') {
    classifier.validation_learning.pricing_interest = true;
  }

  return { json: { ...input, classifier } };
});

