const NOOP_PLAN = {
  stop_active_sequence: false, durable_dnc_intent: false, address_suppression_intent: 'NONE',
  review_hold: false, legal_review_required: false, privacy_review_required: false, reputational_review_required: false,
  human_review_required: false, reply_permitted: false,
